-- helper table for mass update

DROP TABLE IF EXISTS `tmp_spawn_ids_update_mop`;

CREATE TABLE `tmp_spawn_ids_update_mop` (
  `id` int unsigned NOT NULL DEFAULT '0'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


-- Update spawn ids with correct max_build value if present in helper table

UPDATE `creature_spawns` cs
JOIN `tmp_spawn_ids_update_mop` t
    ON t.id = cs.id
SET cs.max_build = 18414
WHERE cs.max_build <> 18414;

-- Delete helper table - thank you for your help

DROP TABLE IF EXISTS `tmp_spawn_ids_update_mop`;

